  const txns = makeTransactions(cfg);
  const watchlist = makeWatchlist(cfg);

  const duplicates = countDuplicates(txns);

  const categoryTotals = new Array(CATEGORIES).fill(0);
  let flagged = 0;
  let feeTotal = 0;
  let reportLines = 0;

  writeFileSync(reportPath, "");
